import React, { useEffect, useState, useMemo } from "react";
import { api } from "../utils/api";

const DAYS = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
const MONTHS = ["January","February","March","April","May","June","July","August","September","October","November","December"];

// ── Local custom events stored in localStorage ──
const STORAGE_KEY = "discipleship_calendar_events";
function loadCustomEvents() {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY) || "[]"); } catch { return []; }
}
function saveCustomEvents(events) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(events));
}

function EventModal({ date, onClose, onSave }) {
  const [form, setForm] = useState({ title: "", type: "event", note: "" });
  const set = (k) => (e) => setForm(f => ({ ...f, [k]: e.target.value }));

  const displayDate = new Date(date + "T12:00:00").toLocaleDateString("en-US", {
    weekday: "long", month: "long", day: "numeric"
  });

  return (
    <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <h3>Add Event</h3>
        <p style={{ fontSize: "0.82rem", color: "var(--text-muted)", marginBottom: 20, marginTop: -12 }}>
          📅 {displayDate}
        </p>
        <div className="form-group">
          <label>Event Title *</label>
          <input className="form-control" value={form.title} onChange={set("title")}
            placeholder="e.g. Guest speaker, Prayer night…" autoFocus />
        </div>
        <div className="form-group">
          <label>Type</label>
          <select className="form-control" value={form.type} onChange={set("type")}>
            <option value="event">📌 General Event</option>
            <option value="session">📅 Class Session</option>
            <option value="assignment">📝 Assignment Due</option>
            <option value="note">💬 Note / Reminder</option>
          </select>
        </div>
        <div className="form-group">
          <label>Note (optional)</label>
          <textarea className="form-control" value={form.note} onChange={set("note")}
            placeholder="Any extra details…" style={{ minHeight: 60 }} />
        </div>
        <div className="modal-actions">
          <button className="btn btn-secondary" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={() => form.title.trim() && onSave({ ...form, date })}
            disabled={!form.title.trim()}>Save Event</button>
        </div>
      </div>
    </div>
  );
}

function DayDetailModal({ date, events, onClose, onDelete }) {
  const displayDate = new Date(date + "T12:00:00").toLocaleDateString("en-US", {
    weekday: "long", month: "long", day: "numeric", year: "numeric"
  });
  return (
    <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <h3 style={{ marginBottom: 4 }}>📅 {displayDate}</h3>
        <p style={{ fontSize: "0.82rem", color: "var(--text-muted)", marginBottom: 20 }}>
          {events.length} event{events.length !== 1 ? "s" : ""} on this day
        </p>
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {events.map((ev, i) => (
            <div key={i} style={{
              display: "flex", alignItems: "flex-start", gap: 10,
              padding: "10px 12px", borderRadius: "var(--radius)",
              background: "var(--surface-2)", border: "1px solid var(--border)",
              borderLeft: `3px solid ${
                ev.type === "session" ? "var(--indigo)" :
                ev.type === "assignment" ? "var(--amber)" :
                ev.type === "note" ? "var(--emerald)" : "var(--sky)"
              }`
            }}>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 600, fontSize: "0.88rem" }}>{ev.label || ev.title}</div>
                {ev.note && <div style={{ fontSize: "0.75rem", color: "var(--text-muted)", marginTop: 3 }}>{ev.note}</div>}
                <span className={`badge ${
                  ev.type === "session" ? "badge-coral" :
                  ev.type === "assignment" ? "badge-warn" :
                  ev.type === "note" ? "badge-green" : "badge-gray"
                }`} style={{ marginTop: 6, fontSize: "0.62rem" }}>
                  {ev.type === "session" ? "Session" : ev.type === "assignment" ? "Assignment" : ev.type === "note" ? "Note" : "Event"}
                </span>
              </div>
              {ev.custom && (
                <button className="btn btn-ghost btn-sm" onClick={() => onDelete(ev.id)}
                  style={{ color: "var(--rose)", flexShrink: 0, padding: "2px 6px" }}>✕</button>
              )}
            </div>
          ))}
        </div>
        <div className="modal-actions">
          <button className="btn btn-secondary" onClick={onClose}>Close</button>
        </div>
      </div>
    </div>
  );
}

export default function Calendar() {
  const [sessions, setSessions]         = useState([]);
  const [assignments, setAssignments]   = useState([]);
  const [customEvents, setCustomEvents] = useState(loadCustomEvents);
  const [today]  = useState(new Date());
  const [current, setCurrent] = useState({ year: new Date().getFullYear(), month: new Date().getMonth() });
  const [addModal, setAddModal]         = useState(null); // date string
  const [detailModal, setDetailModal]   = useState(null); // date string

  useEffect(() => {
    api.getSessions().then(setSessions);
    api.getAssignments().then(setAssignments);
  }, []);

  // Build event map
  const eventMap = useMemo(() => {
    const map = {};
    const add = (date, event) => {
      if (!date) return;
      const key = date.slice(0, 10);
      if (!map[key]) map[key] = [];
      map[key].push(event);
    };
    sessions.forEach(s    => add(s.date,    { type: "session",    label: s.label || "Class Session", custom: false }));
    assignments.forEach(a => { if (a.dueDate) add(a.dueDate, { type: "assignment", label: a.title, custom: false }); });
    customEvents.forEach(e => add(e.date,   { type: e.type, label: e.title, note: e.note, id: e.id, custom: true }));
    return map;
  }, [sessions, assignments, customEvents]);

  // Grid cells
  const days = useMemo(() => {
    const { year, month } = current;
    const firstDay      = new Date(year, month, 1).getDay();
    const daysInMonth   = new Date(year, month + 1, 0).getDate();
    const daysInPrev    = new Date(year, month, 0).getDate();
    const cells = [];
    for (let i = firstDay - 1; i >= 0; i--)
      cells.push({ day: daysInPrev - i, current: false, date: null });
    for (let d = 1; d <= daysInMonth; d++) {
      const date = `${year}-${String(month+1).padStart(2,"0")}-${String(d).padStart(2,"0")}`;
      cells.push({ day: d, current: true, date });
    }
    const remaining = 42 - cells.length;
    for (let d = 1; d <= remaining; d++)
      cells.push({ day: d, current: false, date: null });
    return cells;
  }, [current]);

  const todayStr = `${today.getFullYear()}-${String(today.getMonth()+1).padStart(2,"0")}-${String(today.getDate()).padStart(2,"0")}`;
  const isToday  = (date) => date === todayStr;

  const handleDayClick = (date) => {
    if (!date) return;
    const evs = eventMap[date] || [];
    if (evs.length > 0) setDetailModal(date);
    else setAddModal(date);
  };

  const handleSaveEvent = (form) => {
    const newEvent = { ...form, id: Date.now().toString() };
    const updated  = [...customEvents, newEvent];
    setCustomEvents(updated);
    saveCustomEvents(updated);
    setAddModal(null);
  };

  const handleDeleteEvent = (id) => {
    const updated = customEvents.filter(e => e.id !== id);
    setCustomEvents(updated);
    saveCustomEvents(updated);
    // If no events left on that day, close detail
    const date = detailModal;
    const remaining = (eventMap[date] || []).filter(e => e.id !== id);
    if (remaining.length === 0) setDetailModal(null);
  };

  const prev = () => setCurrent(c => c.month === 0 ? { year: c.year-1, month: 11 } : { ...c, month: c.month-1 });
  const next = () => setCurrent(c => c.month === 11 ? { year: c.year+1, month: 0 } : { ...c, month: c.month+1 });

  // Upcoming events
  const upcoming = useMemo(() => {
    const evs = [];
    sessions.forEach(s     => { if (s.date >= todayStr) evs.push({ date: s.date, type: "session", label: s.label || "Class Session" }); });
    assignments.forEach(a  => { if (a.dueDate >= todayStr) evs.push({ date: a.dueDate, type: "assignment", label: `Due: ${a.title}` }); });
    customEvents.forEach(e => { if (e.date >= todayStr) evs.push({ date: e.date, type: e.type, label: e.title }); });
    return evs.sort((a, b) => a.date.localeCompare(b.date)).slice(0, 10);
  }, [sessions, assignments, customEvents, todayStr]);

  return (
    <div>
      {addModal    && <EventModal date={addModal} onClose={() => setAddModal(null)} onSave={handleSaveEvent} />}
      {detailModal && (
        <DayDetailModal
          date={detailModal}
          events={eventMap[detailModal] || []}
          onClose={() => setDetailModal(null)}
          onDelete={handleDeleteEvent}
        />
      )}

      <div className="page-header">
        <div>
          <h2>Calendar</h2>
          <p>Click any day to add an event or view details</p>
        </div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 260px", gap: 20, alignItems: "start" }}>
        {/* Calendar */}
        <div className="card">
          <div className="cal-nav">
            <h3>{MONTHS[current.month]} {current.year}</h3>
            <button className="cal-nav-btn" onClick={prev}>‹</button>
            <button className="cal-nav-btn" onClick={() => setCurrent({ year: today.getFullYear(), month: today.getMonth() })}>Today</button>
            <button className="cal-nav-btn" onClick={next}>›</button>
          </div>

          <div className="calendar-grid" style={{ marginBottom: 4 }}>
            {DAYS.map(d => <div key={d} className="cal-header">{d}</div>)}
          </div>

          <div className="calendar-grid">
            {days.map((cell, i) => {
              const evs = cell.date ? (eventMap[cell.date] || []) : [];
              return (
                <div key={i}
                  className={`cal-day ${!cell.current ? "other-month" : ""} ${isToday(cell.date) ? "today" : ""}`}
                  onClick={() => handleDayClick(cell.date)}
                  style={{ cursor: cell.current ? "pointer" : "default" }}
                  title={cell.current ? (evs.length > 0 ? `${evs.length} event(s) — click to view` : "Click to add event") : ""}
                >
                  <div className="cal-day-num">{cell.day}</div>
                  {evs.slice(0, 2).map((ev, j) => (
                    <div key={j} className={`cal-event ${ev.type}`}>{ev.label}</div>
                  ))}
                  {evs.length > 2 && (
                    <div style={{ fontSize: "0.6rem", color: "var(--text-light)", marginTop: 1 }}>+{evs.length - 2} more</div>
                  )}
                  {cell.current && evs.length === 0 && (
                    <div className="cal-add-hint">+</div>
                  )}
                </div>
              );
            })}
          </div>

          {/* Legend */}
          <div style={{ display: "flex", gap: 16, marginTop: 16, paddingTop: 14, borderTop: "1px solid var(--border)", flexWrap: "wrap" }}>
            {[
              { cls: "session",    label: "Session" },
              { cls: "assignment", label: "Assignment" },
              { cls: "note",       label: "Note" },
              { cls: "event",      label: "Custom Event" },
            ].map(l => (
              <div key={l.cls} style={{ display: "flex", alignItems: "center", gap: 5 }}>
                <div style={{ width: 10, height: 10, borderRadius: 3,
                  background: l.cls === "session" ? "var(--indigo-dim)" :
                               l.cls === "assignment" ? "var(--amber-dim)" :
                               l.cls === "note" ? "var(--emerald-dim)" : "var(--sky-dim)",
                  border: `1px solid ${l.cls === "session" ? "var(--indigo)" : l.cls === "assignment" ? "var(--amber)" : l.cls === "note" ? "var(--emerald)" : "var(--sky)"}`,
                }} />
                <span style={{ fontSize: "0.72rem", color: "var(--text-muted)" }}>{l.label}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Upcoming sidebar */}
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <div className="card">
            <div className="section-header" style={{ marginBottom: 14 }}>
              <h3>Upcoming</h3>
              <span style={{ fontSize: "0.72rem", color: "var(--text-light)" }}>{upcoming.length} events</span>
            </div>
            {upcoming.length === 0 ? (
              <div style={{ color: "var(--text-muted)", fontSize: "0.85rem", textAlign: "center", padding: "20px 0" }}>Nothing coming up!</div>
            ) : (
              <div style={{ display: "flex", flexDirection: "column", gap: 7 }}>
                {upcoming.map((ev, i) => (
                  <div key={i} style={{
                    padding: "9px 11px", borderRadius: "var(--radius)",
                    background: "var(--surface-2)", border: "1px solid var(--border)",
                    borderLeft: `3px solid ${ev.type === "session" ? "var(--indigo)" : ev.type === "assignment" ? "var(--amber)" : ev.type === "note" ? "var(--emerald)" : "var(--sky)"}`,
                  }}>
                    <div style={{ fontSize: "0.8rem", fontWeight: 600, color: "var(--text)" }}>{ev.label}</div>
                    <div style={{ fontSize: "0.68rem", color: "var(--text-light)", marginTop: 2 }}>
                      {new Date(ev.date + "T12:00:00").toLocaleDateString("en-US", { month: "short", day: "numeric" })}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="card" style={{ background: "var(--indigo-dim)", border: "1px solid rgba(99,102,241,0.2)" }}>
            <div style={{ fontSize: "0.78rem", fontWeight: 600, color: "var(--indigo)", marginBottom: 6 }}>💡 Tip</div>
            <p style={{ fontSize: "0.78rem", color: "var(--text-muted)", lineHeight: 1.6 }}>
              Click any day to add an event. Sessions and assignments you create in the app appear here automatically.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}
